mapper.sql:
SELECT T1.ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, CASE WHEN T1.SHIPVOYAGE_ID IS NULL THEN null ELSE CONCAT(CONCAT(T3.SHIP_NAME, '_') , T4.VOYAGE) END SHIPVOYAGE_LABEL, T3.SHIP_NAME, T1.HATCH, T1.PLAN_NO, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, M1.NM AS STATUS_LABEL, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.EQUIPMENT_NAMES_FRONT, T1.EQUIPMENT_NAMES_BACK, T1.EQUIPMENT_NAMES_ASSIST, T1.EQUIPMENT_NAMES_RESHIPMENT, T1.MASS_NAMES_SOURCE, T1.MASS_NAMES_TARGET, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T1.BUS_CARGO_INFO_ID, T4.CARGO_CATEGORY_CODE, T4.CARGO_CATEGORY_NAME, T2.NUM AS LABOR_NUM, T1.HATCH, T4.LOAD_UNLOAD, t4.CUSTOMER_NAME, T5.SETTLEMENT_BASIS_NAME, T6.CARGO_OWNER_NAME, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, CASE WHEN T1.PROCESS_CODE IS NULL THEN TO_CHAR(T1.PLAN_TYPE) ELSE TO_CHAR((SELECT PLAN_TYPE_CD FROM M_WORK_PROCESS m0 WHERE T1.PROCESS_CODE = m0.PROCESS_CD )) END PLAN_TYPE
FROM T_PRD_WORK_PLAN T1 LEFT JOIN T_PRD_DISPATCH T2 ON T1.ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T1.SHIPVOYAGE_ID = T3.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4.ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_TRUST T5 ON T1.TRUST_ID = T5.ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5.ID = T6.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T7 ON T5.ID = T7.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5.ID = T8.TRUST_ID
AND PLAN_TYPE = #{planType}
and T1.WORK_DATE = #{workDate}
and T1.CLASS_CODE = #{classCode}
and T1.STATUS = #{status}

mapper.select:
SELECT * FROM ( SELECT T1.ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T5.TRUST_NO, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, CASE WHEN T1.SHIPVOYAGE_ID IS NULL THEN null ELSE CONCAT(CONCAT(T3.SHIP_NAME, '_') , T4.VOYAGE) END SHIPVOYAGE_LABEL, CASE WHEN T1.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE CONCAT(CONCAT(TDS.SHIP_NAME, '_') , T4.VOYAGE) END "SHIP_VOYAGE", T3.SHIP_NAME, T4.VOYAGE, T1.HATCH, T1.PLAN_NO, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, M1.NM AS STATUS_LABEL, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T1.BUS_CARGO_INFO_ID, T4.CARGO_CATEGORY_CODE, T4.CARGO_CATEGORY_NAME, NVL(M_SH.HATCH_NUM, 0) HATCH_NUM, T4.LOAD_UNLOAD, T5.PORT_CODE, T5.PORT_NAME, T8.PACKING_CODE, T1.CARGO_CODE, T1.CARGO_NAME, T1.CARGO_OWNER_ID, T1.CARGO_OWNER_NAME, T1.CARGO_INFO_NO, CASE WHEN T1.PROCESS_CODE IS NULL THEN TO_CHAR(T1.PLAN_TYPE) ELSE TO_CHAR((SELECT PLAN_TYPE_CD FROM M_WORK_PROCESS m0 WHERE T1.PROCESS_CODE = m0.PROCESS_CD )) END PLAN_TYPE FROM T_PRD_WORK_PLAN T1 LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T1.SHIPVOYAGE_ID = T3.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4.ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = T4.SHIPVOYAGE_ID LEFT JOIN M_SHIP M_SH ON T3.SHIP_ID = M_SH.ID LEFT JOIN T_BUS_TRUST T5 ON T1.TRUST_ID = T5.ID LEFT JOIN ( select REGEXP_REPLACE( LISTAGG ( TO_CHAR( PACKING_CODE ), ',' ) WITHIN GROUP ( ORDER BY PACKING_CODE ),'([^,]+)(,\1)+', '\1' ) PACKING_CODE ,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5.ID = T8.TRUST_ID
AND T1.WORK_DATE = #{workDate}
AND T1.CLASS_CODE = #{classCode}
AND T1.TRUST_ID = #{trustId,jdbcType=BIGINT}
AND T5.TRUST_NO LIKE #{trustNo_like}
AND T1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND T1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
AND T5.PORT_CODE = #{portCode,jdbcType=VARCHAR}
#{id, jdbcType=VARCHAR}
AND T8.PACKING_CODE LIKE #{packageCode_like}
)
AND PLAN_TYPE = #{planType}
AND SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND VOYAGE = #{voyage}
ORDER BY TRUST_NO ASC

SELECT * FROM ( SELECT T1.ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T5.TRUST_NO, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, CASE WHEN T1.SHIPVOYAGE_ID IS NULL THEN null ELSE CONCAT(CONCAT(T3.SHIP_NAME, '_') , T4.VOYAGE) END SHIPVOYAGE_LABEL, CASE WHEN T1.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE CONCAT(CONCAT(TDS.SHIP_NAME, '_') , T4.VOYAGE) END "SHIP_VOYAGE", T3.SHIP_NAME, T4.VOYAGE, T1.HATCH, T1.PLAN_NO, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, M1.NM AS STATUS_LABEL, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T1.BUS_CARGO_INFO_ID, T4.CARGO_CATEGORY_CODE, T4.CARGO_CATEGORY_NAME, NVL(M1.HATCH_NUM, 0) HATCH_NUM, T4.LOAD_UNLOAD, T5.PORT_CODE, T5.PORT_NAME, T8.PACKING_CODE, T1.CARGO_CODE, T1.CARGO_NAME, T1.CARGO_OWNER_ID, T1.CARGO_OWNER_NAME, CASE WHEN TICKET_COUNT > 0 THEN '已签票' ELSE '待签票' END IS_SIGNED, CASE WHEN T1.PROCESS_CODE IS NULL THEN TO_CHAR(T1.PLAN_TYPE) ELSE TO_CHAR((SELECT PLAN_TYPE_CD FROM M_WORK_PROCESS m0 WHERE T1.PROCESS_CODE = m0.PROCESS_CD )) END PLAN_TYPE FROM T_PRD_WORK_PLAN T1 LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T1.SHIPVOYAGE_ID = T3.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4.ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TDS.ID = T4.SHIPVOYAGE_ID LEFT JOIN (SELECT WORK_PLAN_ID,COUNT(0) TICKET_COUNT FROM T_PRD_WORK_TICKET GROUP BY WORK_PLAN_ID) TPWT ON T1.ID = TPWT.WORK_PLAN_ID LEFT JOIN M_SHIP M1 ON T3.SHIP_ID = M1.ID LEFT JOIN T_BUS_TRUST T5 ON T1.TRUST_ID = T5.ID LEFT JOIN ( select REGEXP_REPLACE( LISTAGG ( TO_CHAR( PACKING_CODE ), ',' ) WITHIN GROUP ( ORDER BY PACKING_CODE ),'([^,]+)(,\1)+', '\1' ) PACKING_CODE ,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5.ID = T8.TRUST_ID
AND T1.WORK_DATE = #{workDate}
AND T1.CLASS_CODE = #{classCode}
AND T1.TRUST_ID = #{trustId,jdbcType=BIGINT}
AND T5.TRUST_NO LIKE #{trustNo_like}
AND T1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND T1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
AND T5.PORT_CODE = #{portCode,jdbcType=VARCHAR}
#{id, jdbcType=VARCHAR}
AND T8.PACKING_CODE LIKE #{packageCode_like}
)
AND PLAN_TYPE = #{planType}
AND SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND VOYAGE = #{voyage}
ORDER BY TRUST_NO ASC

SELECT  * FROM T_PRD_DISPATCH


        AND WORK_PLAN_ID = #{workPlanId,jdbcType=BIGINT}


        AND WORK_PLAN_ID IN

            #{item}

SELECT * FROM ( SELECT T1.ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, CASE WHEN T1.SHIPVOYAGE_ID IS NULL THEN null ELSE CONCAT(CONCAT(T3.SHIP_NAME, '_') , T4.VOYAGE) END SHIPVOYAGE_LABEL, T3.SHIP_NAME, T4.VOYAGE, T1.HATCH, T1.PLAN_NO, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, M1.NM AS STATUS_LABEL, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.EQUIPMENT_NAMES_FRONT, T1.EQUIPMENT_NAMES_BACK, T1.EQUIPMENT_NAMES_ASSIST, T1.EQUIPMENT_NAMES_RESHIPMENT, CONCAT(T1.MASS_NAMES_SOURCE,T1.MASS_NAMES_TARGET) MASS_NAMES, T1.MASS_NAMES_SOURCE, T1.MASS_NAMES_TARGET, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T1.BUS_CARGO_INFO_ID, DECODE(T1.CARGO_CATEGORY_CODE,NULL,T4.CARGO_CATEGORY_CODE,T1.CARGO_CATEGORY_CODE) AS CARGO_CATEGORY_CODE, DECODE(T1.CARGO_CATEGORY_NAME,NULL,T4.CARGO_CATEGORY_NAME,T1.CARGO_CATEGORY_NAME) AS CARGO_CATEGORY_NAME, T2.NUM AS LABOR_NUM, T4.LOAD_UNLOAD, t4.CUSTOMER_NAME, T5.PORT_CODE, T5.PORT_NAME, T5.SETTLEMENT_BASIS_NAME, T5.TRUST_NO, CASE WHEN T6.CARGO_OWNER_NAME IS NULL THEN T1.CARGO_OWNER_NAME ELSE T6.CARGO_OWNER_NAME END CARGO_OWNER_NAME, T6.CARGO_AGENT_NAME, CASE WHEN T6.CARGO_NAME IS NULL THEN T1.CARGO_NAME ELSE T6.CARGO_NAME END CARGO_NAME, CASE WHEN T1.PROCESS_CODE IS NULL THEN TO_CHAR(T1.PLAN_TYPE) ELSE TO_CHAR((SELECT PLAN_TYPE_CD FROM M_WORK_PROCESS m0 WHERE T1.PROCESS_CODE = m0.PROCESS_CD )) END PLAN_TYPE FROM T_PRD_WORK_PLAN T1 LEFT JOIN T_PRD_DISPATCH T2 ON T1.ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' LEFT JOIN T_BUS_TRUST T2_TRUST ON T1.TRUST_ID = T2_TRUST.ID LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T1.SHIPVOYAGE_ID = T3.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4.ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_TRUST T5 ON T1.TRUST_ID = T5.ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_NAME, REGEXP_REPLACE( LISTAGG ( TO_CHAR( PACKING_CODE ), ',' ) WITHIN GROUP ( ORDER BY PACKING_CODE ),'([^,]+)(,\1)+', '\1' ) PACKING_CODE,
REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_CODE ), ',' ) WITHIN GROUP ( ORDER BY CARGO_CODE ), '([^,]+)(,\1)+', '\1' ) CARGO_CODE FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5.ID = T6.TRUST_ID
and T1.STATUS != '10'
and T1.WORK_DATE = #{workDate}
and T1.CLASS_CODE = #{classCode}
and T1.STATUS = #{status}
AND T1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND T5.PORT_CODE = #{portCode,jdbcType=VARCHAR}
AND INSTR(T6.CARGO_OWNER_ID,#{cargoOwnerId})>0
AND INSTR(T6.CARGO_CODE,#{cargoCode})>0
AND T5.TRUST_NO LIKE #{trustNo_like,jdbcType=VARCHAR}
AND T6.PACKING_CODE LIKE #{packageCode_like}
AND T1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
)
AND PLAN_TYPE = #{planType}
AND SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND VOYAGE = #{voyage}
ORDER BY NLSSORT("SHIPVOYAGE_LABEL",'NLS_SORT = SCHINESE_PINYIN_M') ,VOYAGE DESC,PROCESS_NAME DESC

