SELECT WORK_PLAN_ID AS "id", COUNT (1) FROM T_PRD_DISPATCH_SECONDARY WHERE DISPATCH_TYPE = 2 AND WORK_PLAN_ID IN
#{id}
GROUP BY WORK_PLAN_ID HAVING COUNT (1) > 0

SELECT T1.ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, T1.HATCH, T1.PLAN_NO, T1.PLAN_TYPE, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.EQUIPMENT_NAMES_FRONT, T1.EQUIPMENT_NAMES_BACK, T1.EQUIPMENT_NAMES_ASSIST, T1.EQUIPMENT_NAMES_RESHIPMENT, T1.MASS_NAMES_SOURCE, T1.MASS_NAMES_TARGET, T1.RESHIPMENT_TYPE_CODE, T1.BUS_CARGO_INFO_ID, (select CARGO_INFO_NO FROM T_BUS_CARGO_INFO WHERE ID = T1.BUS_CARGO_INFO_ID) CARGO_INFO_NO, T1.CARGO_CATEGORY_CODE, T1.CARGO_CATEGORY_NAME, T2.NUM AS LABOR_NUM, T3.TRUST_NO
FROM T_PRD_WORK_PLAN T1 LEFT JOIN T_PRD_DISPATCH T2 ON T1.ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' LEFT JOIN T_BUS_TRUST T3 ON T1.TRUST_ID = T3.ID
WHERE T1.id = #{id}

mapper.insert:
begin
INSERT INTO T_PRD_WORK_PLAN( ID, COMPANY_ID, COMPANY_NAME, WORK_DATE, CLASS_CODE, CLASS_NAME, TRUST_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, HATCH, PLAN_NO, PLAN_TYPE, PROCESS_CODE, PROCESS_NAME, WORK_CONTENT, DEPT_ID, DEPT_NAME, QUANTITY_PLAN, TON_PLAN, START_TIME_PLAN, END_TIME_PLAN, START_WORK_TIME, END_WORK_TIME, REMARK, STATUS, BERTH_ID, BERTH_NAME, EXAMINE_BY, EXAMINE_BY_NAME, EXAMINE_TIME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, EQUIPMENT_NAMES_FRONT, EQUIPMENT_NAMES_BACK, EQUIPMENT_NAMES_ASSIST, EQUIPMENT_NAMES_RESHIPMENT, MASS_NAMES_SOURCE, MASS_NAMES_TARGET )VALUES( #{item.id, jdbcType=BIGINT}, #{item.companyId, jdbcType=BIGINT}, #{item.companyName, jdbcType=VARCHAR}, #{item.workDate, jdbcType=TIMESTAMP}, #{item.classCode, jdbcType=VARCHAR}, #{item.className, jdbcType=VARCHAR}, #{item.trustId, jdbcType=BIGINT}, #{item.shipvoyageId, jdbcType=BIGINT}, #{item.shipvoyageItemId, jdbcType=BIGINT}, #{item.hatch, jdbcType=VARCHAR}, #{item.planNo, jdbcType=VARCHAR}, #{item.planType, jdbcType=VARCHAR}, #{item.processCode, jdbcType=VARCHAR}, #{item.processName, jdbcType=VARCHAR}, #{item.workContent, jdbcType=VARCHAR}, #{item.deptId, jdbcType=BIGINT}, #{item.deptName, jdbcType=VARCHAR}, #{item.quantityPlan, jdbcType=BIGINT}, #{item.tonPlan,jdbcType=DECIMAL}, #{item.startTimePlan, jdbcType=DATE}, #{item.endTimePlan, jdbcType=DATE}, #{item.startWorkTime, jdbcType=DATE}, #{item.endWorkTime, jdbcType=DATE}, #{item.remark, jdbcType=VARCHAR}, #{item.status, jdbcType=VARCHAR}, #{item.berthId, jdbcType=BIGINT}, #{item.berthName, jdbcType=VARCHAR}, #{item.examineBy, jdbcType=VARCHAR}, #{item.examineByName, jdbcType=VARCHAR}, #{item.examineTime, jdbcType=DATE}, #{loginUserId, jdbcType=BIGINT}, #{loginUserName, jdbcType=VARCHAR}, #{now,jdbcType=TIMESTAMP}, #{item.equipmentNamesFront, jdbcType=VARCHAR}, #{item.equipmentNamesBack, jdbcType=VARCHAR}, #{item.equipmentNamesAssist, jdbcType=VARCHAR}, #{item.equipmentNamesReshipment, jdbcType=VARCHAR}, #{item.massNamesSource, jdbcType=VARCHAR}, #{item.massNamesTarget, jdbcType=VARCHAR} );
end;

mapper.update:
UPDATE T_PRD_WORK_PLAN SET
FRONT_TALLY_BY = #{frontTallyBy, jdbcType=VARCHAR}, FRONT_TALLY_BY_NAME = #{frontTallyByName, jdbcType=VARCHAR}, BACK_TALLY_BY = #{backTallyBy, jdbcType=VARCHAR}, BACK_TALLY_BY_NAME = #{backTallyByName, jdbcType=VARCHAR},
MASS_NAMES_SOURCE = #{massNamesSource, jdbcType=VARCHAR}, MASS_NAMES_TARGET = #{massNamesTarget, jdbcType=VARCHAR},
DISPATCH_BY = #{dispatchBy, jdbcType=VARCHAR}, DISPATCH_BY_NAME = #{dispatchByName, jdbcType=VARCHAR},
UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
id = #{id}

update.foreach:
UPDATE
T_PRD_WORK_PLAN
SET
DISPATCH_BY = #{dto.dispatchBy, jdbcType=VARCHAR},
DISPATCH_BY_NAME = #{dto.dispatchByName, jdbcType=VARCHAR},
UPDATE_BY = #{dto.loginUserId, jdbcType=BIGINT},
UPDATE_BY_NAME = #{dto.loginUserName, jdbcType=VARCHAR},
UPDATE_TIME = #{dto.now}

